const complete=useCallback(async o=>{const an2=Object.entries(notes).flatMap(([s,a])=>a.map(t=>({step:s,label:TREE[s]?.prompt?.slice(0,50)||s,text:t})));const e={id:Date.now().toString(36)+Math.random().toString(36).slice(2,6),date:new Date().toISOString(),prospect:{...p},duration:tm.seconds,outcome:o,notes:an2,rec:rec.trim()||null};setLog(u=>{const nw=[e,...u];saveC(nw);return nw})},[notes,p,tm.seconds,rec]);
