<nav style={{display:"flex",background:"#fff",borderBottom:"2px solid #383154",overflow:"auto"}}>{PHASES.map(ph=>{const a=ph.id===step.phase;return<button key={ph.id} onClick={()=>go(PFS[ph.id])} style={{flex:1,padding:"13px 8px",background:a?ph.color+"18":"transparent",border:"none",borderBottom:a?`3px solid ${ph.color}`:"3px solid transparent",cursor:"pointer",fontFamily:"'Questrial',sans-serif",fontSize:16,fontWeight:a?700:400,color:a?ph.color:"#383154aa",display:"flex",alignItems:"center",justifyContent:"center",gap:6,whiteSpace:"nowrap"}}><span style={{fontSize:18}}>{ph.icon}</span>{ph.label}</button>})}</nav>
